def get_polygonal_numbers():
    polygonal = {3: [], 4: [], 5: [], 6: [], 7: [], 8: []}

    # Triangle: n(n+1)/2
    n = 1
    while True:
        val = n * (n + 1) // 2
        if val >= 10000: break
        if val >= 1000: polygonal[3].append(val)
        n += 1

    # Square: n^2
    n = 1
    while True:
        val = n * n
        if val >= 10000: break
        if val >= 1000: polygonal[4].append(val)
        n += 1

    # Pentagonal: n(3n-1)/2
    n = 1
    while True:
        val = n * (3 * n - 1) // 2
        if val >= 10000: break
        if val >= 1000: polygonal[5].append(val)
        n += 1

    # Hexagonal: n(2n-1)
    n = 1
    while True:
        val = n * (2 * n - 1)
        if val >= 10000: break
        if val >= 1000: polygonal[6].append(val)
        n += 1

    # Heptagonal: n(5n-3)/2
    n = 1
    while True:
        val = n * (5 * n - 3) // 2
        if val >= 10000: break
        if val >= 1000: polygonal[7].append(val)
        n += 1

    # Octagonal: n(3n-2)
    n = 1
    while True:
        val = n * (3 * n - 2)
        if val >= 10000: break
        if val >= 1000: polygonal[8].append(val)
        n += 1

    return polygonal

