    for p in range(3, 9):
        poly_data[p] = []
        for val in polygonal[p]:
            s = str(val)
            poly_data[p].append((int(s[:2]), int(s[2:]), val))

    # We need to find a set of 6 numbers, one of each type.
    # Let's just iterate over all permutations of types and find a cyclic set.

    # To avoid duplicates, we can store the sets as sorted tuples of numbers
    found_sets = set()

    for p_order in itertools.permutations([3, 4, 5, 6, 7, 8]):
        # Backtracking search
        def backtrack(current_order, used_types, current_nums):
            if len(current_order) == 6:
                # Check if the last number connects to the first
                if current_nums[-1][1] == current_nums[0][0]:
                    return current_nums
                return None

            last_num_last2 = current_nums[-1][1]

            next_type = p_order[len(current_order)]
            for first2, last2, val in poly_data[next_type]:
                if first2 == last_num_last2:
                    # Check if this number is already used
                    if val in [n[2] for n in current_nums]:
                        continue
                    res = backtrack(current_order + [next_type], used_types | {next_type}, current_nums + [(first2, last2, val)])
                    if res:
                        return res
            return None

        # Start with all numbers of the first type in the permutation
        first_type = p_order[0]
        for first2, last2, val in poly_data[first_type]:
            res = backtrack([first_type], {first_type}, [(first2, last2, val)])
            if res:
                # Store the set of numbers
                nums = tuple(sorted([n[2] for n in res]))
                found_sets.add(nums)

