def get_primes(limit):
    primes = []
    is_prime = [True] * (limit + 1)
    for p in range(2, limit + 1):
        if is_prime[p]:
            primes.append(p)
            for i in range(p * p, limit + 1, p):
                is_prime[i] = False
    return primes

def solve():
    # n / phi(n) = n / (n * product(1 - 1/p)) = 1 / product(1 - 1/p)
    # To maximize this, we need to minimize product(1 - 1/p).
    # This is equivalent to maximizing the product of distinct prime factors.
    # So we want n to be the product of the smallest primes such that their product <= 1,000,000.

    primes = get_primes(100)
    product = 1
    for p in primes:
        if product * p <= 1000000:
            product *= p
        else:
            break
    return product

print(solve())

