def count_right_triangles(limit):
    counts = [0] * (limit + 1)
    import math

    # L = 2km(m+n)
    # m(m+n) <= limit / 2
    # m^2 < m(m+n) <= limit / 2
    # m < sqrt(limit / 2)

    max_m = int(math.sqrt(limit / 2)) + 2

    for m in range(2, max_m):
        for n in range(1, m):
            if (m - n) % 2 == 1 and math.gcd(m, n) == 1:
                p = 2 * m * (m + n)
                if p > limit:
                    break
                for L in range(p, limit + 1, p):
                    counts[L] += 1

    result = 0
    for L in range(1, limit + 1):
        if counts[L] == 1:
            result += 1

    return result

