def partition_divisible_by_million(limit):
    # Using Euler's pentagonal number theorem to compute p(n)
    # p(n) = sum_{k != 0} (-1)^(k-1) * p(n - k(3k-1)/2)

    p = [0] * (limit + 1)
    p[0] = 1

    pentagonal_numbers = []
    for k in range(1, limit + 1):
        p1 = k * (3 * k - 1) // 2
        p2 = k * (3 * k + 1) // 2
        if p1 <= limit:
            pentagonal_numbers.append((p1, k))
        if p2 <= limit:
            pentagonal_numbers.append((p2, k))
        else:
            break

    pentagonal_numbers.sort()

    for n in range(1, limit + 1):
        for pent, k in pentagonal_numbers:
            if pent > n:
                break

            sign = 1 if (k - 1) % 2 == 0 else -1
            p[n] = (p[n] + sign * p[n - pent]) % 1000000

        if p[n] == 0:
            return n

    return None

