            for item in left_subset:
                right_subset.remove(item)

            left_vals = get_possible_values(left_subset)
            right_vals = get_possible_values(right_subset)

            for l in left_vals:
                for r in right_vals:
                    results.add(l + r)
                    results.add(l - r)
                    results.add(r - l)
                    results.add(l * r)
                    if r != 0:
                        results.add(l / r)
                    if l != 0:
                        results.add(r / l)
    return results

