from itertools import combinations

ops = [
    lambda x, y: x + y,
    lambda x, y: x - y,
    lambda x, y: y - x,
    lambda x, y: x * y,
    lambda x, y: x / y if y != 0 else None,
    lambda x, y: y / x if x != 0 else None,
]

def results(nums):
    if len(nums) == 1:
        return {nums[0]}
    out = set()
    n = len(nums)
    # split into two non-empty groups
    for mask in range(1, 1 << n - 1):
        pass
    # recursive pairwise reduction is simpler
    if len(nums) == 2:
        a, b = nums
        for op in ops:
            try:
                r = op(a, b)
            except ZeroDivisionError:
                continue
            if r is not None:
                out.add(r)
        return out
    # choose ordered pair and reduce
    L = list(nums)
    for i in range(len(L)):
        for j in range(i + 1, len(L)):
            a, b = L[i], L[j]
            rest = [L[k] for k in range(len(L)) if k != i and k != j]
            for op in ops:
                try:
                    r = op(a, b)
                except ZeroDivisionError:
                    continue
                if r is None:
                    continue
                out |= results(rest + [r])
    return out

# Better memoized recursive generation using tuples of Fractions
from functools import lru_cache

@lru_cache(None)
def gen(state):
    state = tuple(sorted(state))
    if len(state) == 1:
        return {state[0]}
    out = set()
    n = len(state)
    for i in range(n):
        for j in range(i + 1, n):
            a, b = state[i], state[j]
            rest = list(state[:i] + state[i+1:j] + state[j+1:])
            candidates = [a + b, a - b, b - a, a * b]
            if b != 0:
                candidates.append(a / b)
            if a != 0:
                candidates.append(b / a)
            for r in candidates:
                out |= gen(tuple(rest + [r]))
    return out

