                        new_list_base = [x for k, x in enumerate(current_list) if k not in (i, j)]
                        for pos in range(len(new_list_base) + 1):
                            new_list = new_list_base[:pos] + [val] + new_list_base[pos:]
                            sub_results = helper(new_list)
                            results.update(sub_results)
                    elif op == '-':
                        val = A - B
                        new_list_base = [x for k, x in enumerate(current_list) if k not in (i, j)]
                        for pos in range(len(new_list_base) + 1):
                            new_list = new_list_base[:pos] + [val] + new_list_base[pos:]
                            sub_results = helper(new_list)
                            results.update(sub_results)
                        val2 = B - A
                        for pos in range(len(new_list_base) + 1):
                            new_list2 = new_list_base[:pos] + [val2] + new_list_base[pos:]
                            sub_results2 = helper(new_list2)
                            results.update(sub_results2)
                    elif op == '*':
                        val = A * B
                        new_list_base = [x for k, x in enumerate(current_list) if k not in (i, j)]
                        for pos in range(len(new_list_base) + 1):
                            new_list = new_list_base[:pos] + [val] + new_list_base[pos:]
                            sub_results = helper(new_list)
                            results.update(sub_results)
                    elif op == '/':
                        if B != 0:
                            val = A / B
                            new_list_base = [x for k, x in enumerate(current_list) if k not in (i, j)]
                            for pos in range(len(new_list_base) + 1):
                                new_list = new_list_base[:pos] + [val] + new_list_base[pos:]
                                sub_results = helper(new_list)
                                results.update(sub_results)
                        if A != 0:
                            val2 = B / A
                            new_list_base = [x for k, x in enumerate(current_list) if k not in (i, j)]
                            for pos in range(len(new_list_base) + 1):
                                new_list2 = new_list_base[:pos] + [val2] + new_list_base[pos:]
                                sub_results2 = helper(new_list2)
                                results.update(sub_results2)
        return results
    nums_frac = [Fraction(x) for x in nums]
    possible_values = set()
    for perm in itertools.permutations(nums_frac):
        possible_values.update(helper(list(perm)))
    return possible_values
